587→        columns: (f.columns || []).filter(c => c.id !== action.columnId),
588→        walls: f.walls.map(w => detachColumnAttachments(w, f.columns || [], action.columnId)),
589→        beams: (f.beams || []).filter(beam => (
590→          beam.startRef?.id !== action.columnId && beam.endRef?.id !== action.columnId
591→        )),
592→      }));
593→
594→    case 'PHASE_ADD':
595→      return applyProjectUpdate(state, {
596→        ...state.project,
597→        updatedAt: new Date().toISOString(),
598→        phases: sortPhases([...(state.project.phases || []), action.phase]),
599→      });
600→
601→    case 'PHASE_UPDATE':
602→      return applyProjectUpdate(state, {
603→        ...state.project,
604→        updatedAt: new Date().toISOString(),
605→        phases: sortPhases(
606→          (state.project.phases || []).map(p =>
607→            p.id === action.phase.id ? { ...p, ...action.phase } : p
608→          )
609→        ),
610→      });
611→
612→    case 'PHASE_DELETE': {
613→      const phaseId = action.phaseId;
614→      const nullifyPhase = (obj) =>
615→        obj.phaseId === phaseId ? { ...obj, phaseId: null } : obj;
616→      const phaseArrayKeys = [
617→        'walls', 'doors', 'windows', 'columns', 'beams', 'slabs',
618→        'stairs', 'landings', 'fixtures', 'rooms', 'railings',
619→      ];
620→      return applyProjectUpdate(state, {
621→        ...state.project,
622→        updatedAt: new Date().toISOString(),
623→        phases: (state.project.phases || []).filter(p => p.id !== phaseId),
624→        floors: state.project.floors.map(floor => {
625→          const updated = { ...floor };
626→          for (const key of phaseArrayKeys) {
627→            if (updated[key]) {
628→              updated[key] = updated[key].map(nullifyPhase);
629→            }
630→          }
631→          return updated;
632→        }),
633→        sheets: (state.project.sheets || []).map(sheet => ({
634→          ...sheet,
635→          viewports: (sheet.viewports || []).map(vp =>
636→            vp.phaseId === phaseId
637→              ? { ...vp, phaseId: null, phaseViewMode: 'all' }
638→              : vp
639→          ),
640→        })),
641→      });
642→    }
643→
644→    case 'PHASE_REORDER':
645→      return applyProjectUpdate(state, {
646→        ...state.project,
647→        updatedAt: new Date().toISOString(),
648→        phases: action.phases,
649→      });
650→
651→    case 'MARK_SAVED':
652→      return {
653→        ...state,
654→        isDirty: false,
655→        lastSavedAt: new Date().toISOString(),
656→        savedSnapshot: snapshotProject(state.project),
657→      };
658→
659→    case 'UNDO': {
660→      if (state.history.length === 0) return state;
661→      const previousProject = state.history[state.history.length - 1];
662→      return {
663→        ...state,
664→        project: previousProject,
665→        history: state.history.slice(0, -1),
666→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
667→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
668→      };
669→    }
670→
671→    case 'REDO': {
672→      if (state.future.length === 0) return state;
673→      const nextProject = state.future[0];
674→      return {
675→        ...state,
676→        project: nextProject,
677→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
678→        future: state.future.slice(1),
679→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
680→      };
681→    }
682→
683→    default:
684→      return state;
685→  }
686→}
687→
688→const initialProject = createProject();
689→
690→const initialState = {
691→  project: initialProject,
692→  isDirty: false,
693→  lastSavedAt: null,
694→  savedSnapshot: snapshotProject(initialProject),
695→  history: [],
696→  future: [],
697→};
698→
699→export function ProjectProvider({ children }) {
700→  const [state, dispatch] = useReducer(projectReducer, initialState);
701→  return (
702→    <ProjectContext.Provider value={{ state, dispatch }}>
703→      {children}
704→    </ProjectContext.Provider>
705→  );
706→}
707→
708→export function useProject() {
709→  const ctx = useContext(ProjectContext);
710→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
711→  const { state, dispatch } = ctx;
712→
713→  const duplicateFloor = (floorId) => {
714→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
715→    return floor ? createDuplicatedFloor(floor) : null;
716→  };
717→
718→  return {
719→    project: state.project,
720→    isDirty: state.isDirty,
721→    lastSavedAt: state.lastSavedAt,
722→    canUndo: state.history.length > 0,
723→    canRedo: state.future.length > 0,
724→    dispatch,
725→    duplicateFloor,
726→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
727→  };
728→}
