              <button
                type="button"
                className={styles.floorActionBtn}
                onClick={() => handleMovePhase(phase, -1)}
                title="Move up"
                disabled={phase.order === 0}
              >
                <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.floorActionIcon}>
                  <path d="M7 3l4 5H3z" fill="currentColor" />
