import { useState } from 'react';
import Modal from './Modal';
import { PHASE_TEMPLATES, PHASE_COLORS } from '@/domain/phaseModels';
import styles from './NewProjectModal.module.css';
import modalStyles from './Modal.module.css';

export default function NewProjectModal({ onConfirm, onClose }) {
  const [name, setName] = useState('Untitled Project');
  const [selectedTemplateId, setSelectedTemplateId] = useState('empty');

  const handleSubmit = (e) => {
    e.preventDefault();
    onConfirm({ name: name.trim() || 'Untitled Project', templateId: selectedTemplateId });
  };

  return (
    <Modal title="New Project" onClose={onClose}>
      <form onSubmit={handleSubmit} className={styles.form}>
        <div>
          <label className={styles.label}>Project Name</label>
          <input
            className={styles.nameInput}
            value={name}
            onChange={(e) => setName(e.target.value)}
            autoFocus
            onFocus={(e) => e.target.select()}
          />
        </div>

        <div>
          <label className={styles.label}>Phase Template</label>
          <div className={styles.templateGrid}>
            {PHASE_TEMPLATES.map((template) => (
              <div
                key={template.id}
                className={selectedTemplateId === template.id ? styles.templateCardSelected : styles.templateCard}
                onClick={() => setSelectedTemplateId(template.id)}
              >
                <span className={styles.templateName}>{template.name}</span>
                <span className={styles.templateDesc}>{template.description}</span>
                <div className={styles.templatePhases}>
                  {template.phases.map((phase, i) => (
                    <span key={i} className={styles.templatePhaseDot}>
                      <span
                        className={styles.templatePhaseDotColor}
                        style={{ background: PHASE_COLORS[phase.colorIndex % PHASE_COLORS.length] }}
                      />
                      {phase.name}
                    </span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className={styles.actions}>
          <button type="button" className={modalStyles.modalBtn} onClick={onClose}>
            Cancel
          </button>
          <button type="submit" className={modalStyles.modalBtn}>
            Create
          </button>
        </div>
      </form>
    </Modal>
  );
}

